// Pipeline A: Demo Call Processing
// Extract transcript from webhook payload
const transcript = $input.first().json.transcript;
const filename = $input.first().json.filename || 'unknown';

if (!transcript) {
  throw new Error('No transcript provided in webhook payload');
}

// Generate account_id from transcript header
let companyName = 'unknown';
const headerMatch = transcript.match(/(?:TRANSCRIPT|CALL).*?—\s*(.+)/);
if (headerMatch) {
  companyName = headerMatch[1].trim();
}
const accountId = companyName.toLowerCase().replace(/[^a-z0-9\s]/g, '').replace(/\s+/g, '_');

return [{
  json: {
    transcript: transcript,
    filename: filename,
    company_name: companyName,
    account_id: accountId,
    pipeline: 'demo',
    timestamp: new Date().toISOString()
  }
}];

// Pipeline B: Onboarding Call Processing
const transcript = $input.first().json.transcript;
const filename = $input.first().json.filename || 'unknown';
const accountId = $input.first().json.account_id;

if (!transcript) {
  throw new Error('No transcript provided in webhook payload');
}
if (!accountId) {
  throw new Error('No account_id provided. Process demo call first.');
}

return [{
  json: {
    transcript: transcript,
    filename: filename,
    account_id: accountId,
    pipeline: 'onboarding',
    timestamp: new Date().toISOString()
  }
}];

// Parse LLM response for memo extraction
const response = $input.first().json;
let memo;

try {
  // Ollama returns response in 'response' field
  const rawResponse = response.response || response.body || JSON.stringify(response);
  memo = typeof rawResponse === 'string' ? JSON.parse(rawResponse) : rawResponse;
} catch (e) {
  // Fallback: try to extract JSON from response
  const text = response.response || '';
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    memo = JSON.parse(match[0]);
  } else {
    throw new Error('Failed to parse memo from LLM response: ' + e.message);
  }
}

// Ensure required fields
memo.account_id = memo.account_id || $('Parse Demo Transcript').first().json.account_id;
memo.company_name = memo.company_name || $('Parse Demo Transcript').first().json.company_name;

return [{ json: { memo: memo, account_id: memo.account_id, pipeline: 'demo' } }];

// Parse agent spec response
const response = $input.first().json;
let spec;

try {
  const rawResponse = response.response || response.body || JSON.stringify(response);
  spec = typeof rawResponse === 'string' ? JSON.parse(rawResponse) : rawResponse;
} catch (e) {
  const text = response.response || '';
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    spec = JSON.parse(match[0]);
  } else {
    throw new Error('Failed to parse spec: ' + e.message);
  }
}

spec.version = spec.version || 'v1';
const memo = $('Parse Memo Response').first().json.memo;
const accountId = memo.account_id;

return [{
  json: {
    memo: memo,
    spec: spec,
    account_id: accountId,
    pipeline: 'demo'
  }
}];

// Save v1 artifacts to local filesystem
const fs = require('fs');
const path = require('path');

const data = $input.first().json;
const accountId = data.account_id;

// Output directory (mounted volume)
const baseDir = '/data/outputs/accounts';
const v1Dir = path.join(baseDir, accountId, 'v1');

// Create directories
fs.mkdirSync(v1Dir, { recursive: true });

// Save memo
fs.writeFileSync(
  path.join(v1Dir, 'memo.json'),
  JSON.stringify(data.memo, null, 2),
  'utf8'
);

// Save agent spec
fs.writeFileSync(
  path.join(v1Dir, 'agent_spec.json'),
  JSON.stringify(data.spec, null, 2),
  'utf8'
);

// Save task tracker
const task = {
  task_id: require('crypto').createHash('md5').update(accountId + '_demo').digest('hex').substring(0, 8),
  account_id: accountId,
  company_name: data.memo.company_name,
  phase: 'demo',
  status: 'completed',
  created_at: new Date().toISOString(),
  steps_completed: ['transcript_received', 'memo_extracted', 'agent_spec_generated', 'artifacts_saved']
};

fs.writeFileSync(
  path.join(baseDir, accountId, 'task_demo.json'),
  JSON.stringify(task, null, 2),
  'utf8'
);

return [{
  json: {
    success: true,
    account_id: accountId,
    company_name: data.memo.company_name,
    pipeline: 'demo',
    output_path: v1Dir,
    message: `Demo call processed successfully for ${data.memo.company_name}`
  }
}];

// Load existing v1 memo for onboarding update
const fs = require('fs');
const path = require('path');

const accountId = $input.first().json.account_id;
const transcript = $input.first().json.transcript;

const baseDir = '/data/outputs/accounts';
const v1MemoPath = path.join(baseDir, accountId, 'v1', 'memo.json');
const v1SpecPath = path.join(baseDir, accountId, 'v1', 'agent_spec.json');

if (!fs.existsSync(v1MemoPath)) {
  throw new Error(`No v1 data found for account ${accountId}. Process demo call first.`);
}

const existingMemo = JSON.parse(fs.readFileSync(v1MemoPath, 'utf8'));
const existingSpec = JSON.parse(fs.readFileSync(v1SpecPath, 'utf8'));

return [{
  json: {
    existing_memo: existingMemo,
    existing_spec: existingSpec,
    transcript: transcript,
    account_id: accountId
  }
}];

// Parse updated memo and generate v2 spec request
const response = $input.first().json;
let updatedMemo;

try {
  const rawResponse = response.response || JSON.stringify(response);
  updatedMemo = typeof rawResponse === 'string' ? JSON.parse(rawResponse) : rawResponse;
} catch (e) {
  const text = response.response || '';
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    updatedMemo = JSON.parse(match[0]);
  } else {
    throw new Error('Failed to parse updated memo: ' + e.message);
  }
}

const accountId = $('Parse Onboarding Transcript').first().json.account_id;
updatedMemo.account_id = accountId;

return [{
  json: {
    updated_memo: updatedMemo,
    account_id: accountId,
    existing_memo: $('Load Existing v1 Data').first().json.existing_memo,
    existing_spec: $('Load Existing v1 Data').first().json.existing_spec
  }
}];

// Parse v2 spec, generate changelog, and save everything
const fs = require('fs');
const path = require('path');

const response = $input.first().json;
let updatedSpec;

try {
  const rawResponse = response.response || JSON.stringify(response);
  updatedSpec = typeof rawResponse === 'string' ? JSON.parse(rawResponse) : rawResponse;
} catch (e) {
  const text = response.response || '';
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    updatedSpec = JSON.parse(match[0]);
  } else {
    throw new Error('Failed to parse v2 spec: ' + e.message);
  }
}

updatedSpec.version = 'v2';

const prevData = $('Parse Updated Memo').first().json;
const accountId = prevData.account_id;
const updatedMemo = prevData.updated_memo;
const existingMemo = prevData.existing_memo;
const existingSpec = prevData.existing_spec;

// Generate changelog
let changelog = `# Changelog: ${updatedMemo.company_name || accountId}\n`;
changelog += `**Generated**: ${new Date().toISOString()}\n`;
changelog += `**Account ID**: ${accountId}\n\n`;
changelog += `## Account Memo Changes\n\n`;

const fieldsToCompare = [
  ['services_supported', 'Services'],
  ['emergency_definition', 'Emergency Definitions'],
  ['business_hours', 'Business Hours'],
  ['integration_constraints', 'Integrations'],
  ['notes', 'Notes']
];

let hasChanges = false;
for (const [field, label] of fieldsToCompare) {
  const v1 = JSON.stringify(existingMemo[field] || '');
  const v2 = JSON.stringify(updatedMemo[field] || '');
  if (v1 !== v2) {
    hasChanges = true;
    changelog += `### ${label}\n`;
    changelog += `- **v1**: ${v1}\n`;
    changelog += `- **v2**: ${v2}\n\n`;
  }
}

if (!hasChanges) {
  changelog += '_No field-level changes detected._\n\n';
}

changelog += `## Agent Spec Changes\n\n`;
changelog += `*Version upgraded from v1 → v2*\n`;

// Save v2 artifacts
const baseDir = '/data/outputs/accounts';
const v2Dir = path.join(baseDir, accountId, 'v2');
fs.mkdirSync(v2Dir, { recursive: true });

fs.writeFileSync(path.join(v2Dir, 'memo.json'), JSON.stringify(updatedMemo, null, 2), 'utf8');
fs.writeFileSync(path.join(v2Dir, 'agent_spec.json'), JSON.stringify(updatedSpec, null, 2), 'utf8');
fs.writeFileSync(path.join(baseDir, accountId, 'changelog.md'), changelog, 'utf8');

// Task tracker
const task = {
  task_id: require('crypto').createHash('md5').update(accountId + '_onboarding').digest('hex').substring(0, 8),
  account_id: accountId,
  company_name: updatedMemo.company_name,
  phase: 'onboarding',
  status: 'completed',
  created_at: new Date().toISOString(),
  steps_completed: ['transcript_received', 'v1_loaded', 'memo_updated', 'spec_v2_generated', 'changelog_created', 'artifacts_saved']
};
fs.writeFileSync(path.join(baseDir, accountId, 'task_onboarding.json'), JSON.stringify(task, null, 2), 'utf8');

return [{
  json: {
    success: true,
    account_id: accountId,
    company_name: updatedMemo.company_name,
    pipeline: 'onboarding',
    message: `Onboarding processed successfully for ${updatedMemo.company_name}`
  }
}];

// Error handler — log and return structured error
const error = $input.first().json;
const errorMessage = error.message || error.error || 'Unknown error occurred';

console.error('Pipeline Error:', errorMessage);

return [{
  json: {
    success: false,
    error: errorMessage,
    timestamp: new Date().toISOString(),
    suggestion: 'Check Ollama is running and the model is pulled. Try: docker exec ollama ollama pull llama3.2:3b'
  }
}];
